import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useCart } from "./CartContext";

const medicines = [
  "Paracetamol",
  "Ibuprofen",
  "Amoxicillin",
  "Cetirizine",
  "Vitamin C",
  "Dolo 650",
  "Azithromycin"
];

function Help() {
  const navigate = useNavigate();
  const { cartItems, addToCart, increaseQty, decreaseQty } = useCart();

  const [activeService, setActiveService] = useState("medicines");

  const services = [
    { key: "medicines", label: "Medicines" },
    { key: "ambulance", label: "Ambulance" },
    { key: "doctor", label: "Doctor" },
    { key: "blood", label: "Blood" },
    { key: "emergency", label: "Emergency" }
  ];

  return (
    <div className="help-container">

      {/* HEADER */}
      <div className="header">
        <h2>Local Help Services</h2>

        <button
          className="cart-btn"
          onClick={() => navigate("/cart")}
        >
          🛒 Cart ({cartItems.reduce((s, i) => s + i.quantity, 0)})
        </button>
      </div>

      {/* SERVICE TABS */}
      <div className="service-tabs">
        {services.map((s) => (
          <button
            key={s.key}
            className={activeService === s.key ? "tab active" : "tab"}
            onClick={() => setActiveService(s.key)}
          >
            {s.label}
          </button>
        ))}
      </div>

      {/* MEDICINES SECTION */}
      {activeService === "medicines" && (
        <div className="medicine-grid">

          {medicines.map((med, index) => {
            const item = cartItems.find(i => i.name === med);
            const qty = item ? item.quantity : 0;

            return (
              <div key={index} className="medicine-card">

                <h4>{med}</h4>

                {qty === 0 ? (
                  <button
                    onClick={() =>
                      addToCart({
                        id: index + 1,
                        name: med
                      })
                    }
                  >
                    Add to Cart
                  </button>
                ) : (
                  <div className="qty-controls">

                    <button onClick={() => decreaseQty(item.id)}>
                      -
                    </button>

                    <span>{qty}</span>

                    <button
                      onClick={() => increaseQty(item.id)}
                      disabled={qty >= 5}
                    >
                      +
                    </button>

                  </div>
                )}

                {qty >= 5 && (
                  <small className="limit-text">Max limit reached</small>
                )}

              </div>
            );
          })}
        </div>
      )}

      {/* UNDER DEVELOPMENT */}
      {activeService !== "medicines" && (
        <div className="maintenance-box">
          <h3>🚧 Coming Soon</h3>
          <p>This service is currently under development.</p>
        </div>
      )}

    </div>
  );
}

export default Help;
